+func TestTierForWidth(t *testing.T) {
+	tests := []struct {
+		width int
+		want  Tier
+	}{
+		{100, TierNarrow},
+		{120, TierSplit},
+		{150, TierSplit},
+		{200, TierWide},
+		{239, TierWide},
+		{240, TierUltra},
+		{319, TierUltra},
+		{320, TierMega},
+		{400, TierMega},
+	}
+
+	for _, tt := range tests {
+		if got := TierForWidth(tt.width); got != tt.want {
+			t.Errorf("TierForWidth(%d) = %v, want %v", tt.width, got, tt.want)
+		}
+	}
+}
